import type { ColumnProfile } from "@/lib/types/shared";

export interface DatasetSchemaField {
  name: string;
  type: string;
}

export type DatasetSourceType = "csv" | "tsv" | "excel" | "parquet" | "json" | "jsonl" | "text";

export interface Dataset {
  id: string;
  name: string;
  source_type: DatasetSourceType;
  /** "input" = uploaded by user; "output" = generated by a flow run. */
  dataset_kind: "input" | "output";
  is_disabled: boolean;
  project_id: string | null;
  /** Highest version number available (latest snapshot). */
  latest_version: number;
  /** Total number of versions uploaded under this name. */
  version_count: number;
  // The backend exposes these under aliased names (column_schema / data_sample);
  // `location` is intentionally never sent to the client. They reflect the latest version.
  column_schema: DatasetSchemaField[] | null;
  data_sample: Record<string, unknown>[] | null;
  column_profile: ColumnProfile[] | null;
  /** The ORIGINAL upload's dialect (delimiter/encoding/decimal/sheet) when it
   *  wasn't the default; the stored copy is normalized at ingest. Optional so
   *  test fixtures predating the field stay valid. */
  parse_options?: Record<string, string | number> | null;
  created_at: string;
  updated_at: string;
}

/** Optional dialect overrides for an upload; omitted fields are auto-detected. */
export interface UploadParseOptions {
  delimiter?: string;
  encoding?: string;
  decimal?: string;
  sheet?: string;
}

export interface DatasetVersion {
  id: string;
  version_number: number;
  row_count: number;
  column_schema: DatasetSchemaField[] | null;
  column_profile: ColumnProfile[] | null;
  source_run_id: string | null;
  created_at: string;
}
